class Solution:
    def minDamage(self, power, damage, health):
        # Independent brute force: try every permutation of kill order directly
        # (only used on small rosters) instead of trusting the sort comparator.
        import itertools
        n = len(damage)
        t = [-(-h // power) for h in health]
        best = None
        for perm in itertools.permutations(range(n)):
            suf = [0] * (n + 1)
            for k in range(n - 1, -1, -1):
                suf[k] = suf[k + 1] + damage[perm[k]]
            total = 0
            for pos, i in enumerate(perm):
                total += t[i] * suf[pos]
            if best is None or total < best:
                best = total
        return best

