import functools

class Solution:
    def minDamage(self, power, damage, health):
        n = len(damage)
        t = [-(-h // power) for h in health]

        def cmp(i, j):
            lhs = t[i] * damage[j]
            rhs = t[j] * damage[i]
            if lhs < rhs:
                return -1
            if lhs > rhs:
                return 1
            return 0

        idx = sorted(range(n), key=functools.cmp_to_key(cmp))
        suffix_sums = [0] * (n + 1)
        for k in range(n - 1, -1, -1):
            suffix_sums[k] = suffix_sums[k + 1] + damage[idx[k]]
        total = 0
        for pos, i in enumerate(idx):
            total += t[i] * suffix_sums[pos]
        return total

