var minDamage = function(power, damage, health) {
    const n = damage.length;
    const t = new Array(n);
    for (let i = 0; i < n; i++) t[i] = Math.ceil(health[i] / power);
    const idx = Array.from({length: n}, (_, i) => i);
    idx.sort((a, b) => t[a] * damage[b] - t[b] * damage[a]);
    const suffix = new Array(n + 1).fill(0n);
    for (let k = n - 1; k >= 0; k--) {
        suffix[k] = suffix[k + 1] + BigInt(damage[idx[k]]);
    }
    let total = 0n;
    for (let pos = 0; pos < n; pos++) {
        total += BigInt(t[idx[pos]]) * suffix[pos];
    }
    return Number(total);
};
